/**
 * QA Browser Automation Script for BRUTALWAV DAW
 * Tests all major panels, interactions, keyboard shortcuts, metering, responsive behavior, and accessibility.
 */

import { chromium } from "playwright";
import { writeFileSync, mkdirSync } from "fs";
import { join } from "path";

const BASE_URL = "http://localhost:5173";
const SCREENSHOT_DIR = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/screenshots";
const REPORT_PATH = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/qa-report.md";

mkdirSync(SCREENSHOT_DIR, { recursive: true });

const findings = [];
const passed = [];
const screenshots = [];

function finding(severity, category, what, where, repro, justification) {
  findings.push({ severity, category, what, where, repro, justification });
}

function pass(description) {
  passed.push(description);
}

async function screenshot(page, name, description) {
  const path = join(SCREENSHOT_DIR, `${name}.png`);
  await page.screenshot({ path, fullPage: false });
  screenshots.push({ name, path: `screenshots/${name}.png`, description });
  return path;
}

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
    // Enable cross-origin isolation by bypassing CSP for testing
  });

  // Capture console messages
  const consoleMsgs = [];
  const pageErrors = [];

  const page = await context.newPage();
  page.on("console", (msg) => consoleMsgs.push({ type: msg.type(), text: msg.text() }));
  page.on("pageerror", (err) => pageErrors.push(err.message));

  // Network tracking
  const networkErrors = [];
  page.on("response", (res) => {
    if (res.status() >= 400) {
      networkErrors.push({ url: res.url(), status: res.status() });
    }
  });

  console.log("=== Phase 1: Navigate to app ===");
  try {
    await page.goto(BASE_URL, { waitUntil: "networkidle", timeout: 15000 });
  } catch (e) {
    console.error("Failed to navigate:", e.message);
    finding("P0", "INFRA", "App failed to load", BASE_URL, "Navigate to " + BASE_URL, "Application not reachable");
    await browser.close();
    generateReport();
    return;
  }

  // Screenshot initial state (ClickToStart screen)
  await screenshot(page, "01-click-to-start", "Initial ClickToStart screen before audio engine init");

  // Check cross-origin isolation
  const crossOriginOk = await page.evaluate(() => window.crossOriginIsolated);
  if (crossOriginOk) {
    pass("Cross-origin isolation is active (COOP/COEP headers working)");
  } else {
    finding("P1", "INFRA", "Cross-origin isolation not active", BASE_URL, "Check window.crossOriginIsolated", "SharedArrayBuffer and AudioWorklet require cross-origin isolation");
  }

  // Check what's on screen
  const clickToStartVisible = await page.locator("text=Click to Start").isVisible().catch(() => false);
  const crossOriginErrorVisible = await page.locator("text=Cross-Origin").isVisible().catch(() => false);

  if (crossOriginErrorVisible) {
    await screenshot(page, "02-cross-origin-error", "CrossOriginError screen shown");
    finding("P1", "INFRA", "CrossOriginError displayed - COOP/COEP headers missing", BASE_URL, "Load the app", "App cannot function without cross-origin isolation");
    await browser.close();
    generateReport();
    return;
  }

  if (clickToStartVisible) {
    pass("ClickToStart screen renders correctly");
    // Click to start the audio engine
    const startBtn = page.locator("button").filter({ hasText: /start/i });
    if (await startBtn.isVisible()) {
      await startBtn.click();
      // Wait for DAW shell to appear
      await page.waitForSelector('[data-testid="daw-shell"]', { timeout: 5000 }).catch(() => null);
    }
  }

  // Wait a moment for rendering
  await page.waitForTimeout(1000);

  const dawShellVisible = await page.locator('[data-testid="daw-shell"]').isVisible().catch(() => false);
  if (!dawShellVisible) {
    await screenshot(page, "02b-no-daw-shell", "DawShell did not appear after clicking start");
    finding("P1", "FUNC", "DawShell did not render after clicking start", BASE_URL, "Click start button", "Main app UI not loading");
    // Try continuing anyway
  }

  console.log("=== Phase 2: Screenshot all major panels ===");

  // Full DAW view
  await screenshot(page, "02-daw-full-view", "Full DAW view at 1440x900");

  // Transport bar
  const toolbar = page.locator('[data-testid="toolbar"]');
  if (await toolbar.isVisible()) {
    await toolbar.screenshot({ path: join(SCREENSHOT_DIR, "03-transport-bar.png") });
    screenshots.push({ name: "03-transport-bar", path: "screenshots/03-transport-bar.png", description: "Transport bar with BPM, play/stop, loop, metronome" });
    pass("Transport bar renders with BPM input, Play, Stop, Loop, and Metronome controls");
  } else {
    finding("P1", "FUNC", "Transport bar not visible", "[data-testid='toolbar']", "Load the DAW", "Core UI element missing");
  }

  // Arrangement panel
  const arrangement = page.locator('[data-testid="arrangement-panel"]');
  if (await arrangement.isVisible()) {
    await arrangement.screenshot({ path: join(SCREENSHOT_DIR, "04-arrangement-panel.png") });
    screenshots.push({ name: "04-arrangement-panel", path: "screenshots/04-arrangement-panel.png", description: "Arrangement panel with tracks canvas" });
    pass("Arrangement panel renders with canvas");
  } else {
    finding("P1", "FUNC", "Arrangement panel not visible", "[data-testid='arrangement-panel']", "Load the DAW", "Core panel missing");
  }

  // Mixer panel
  const mixer = page.locator('[data-testid="mixer-panel"]');
  if (await mixer.isVisible()) {
    await mixer.screenshot({ path: join(SCREENSHOT_DIR, "05-mixer-panel.png") });
    screenshots.push({ name: "05-mixer-panel", path: "screenshots/05-mixer-panel.png", description: "Mixer panel with channel strips" });
    pass("Mixer panel renders with channel strips");
  } else {
    finding("P1", "FUNC", "Mixer panel not visible", "[data-testid='mixer-panel']", "Load the DAW", "Core panel missing");
  }

  // Instrument panel
  const instrument = page.locator('[data-testid="instrument-panel"]');
  if (await instrument.isVisible()) {
    await instrument.screenshot({ path: join(SCREENSHOT_DIR, "06-instrument-panel.png") });
    screenshots.push({ name: "06-instrument-panel", path: "screenshots/06-instrument-panel.png", description: "Instrument panel (synth editor or placeholder)" });
    pass("Instrument panel renders");
  } else {
    finding("P2", "FUNC", "Instrument panel not visible", "[data-testid='instrument-panel']", "Load the DAW", "Panel missing or collapsed");
  }

  // Media pool
  const mediaPool = page.locator('[data-testid="media-pool-panel"]');
  if (await mediaPool.isVisible()) {
    await mediaPool.screenshot({ path: join(SCREENSHOT_DIR, "07-media-pool.png") });
    screenshots.push({ name: "07-media-pool", path: "screenshots/07-media-pool.png", description: "Media pool panel" });
    pass("Media pool panel renders");
  } else {
    finding("P2", "FUNC", "Media pool panel not visible", "[data-testid='media-pool-panel']", "Load the DAW", "Panel missing or collapsed");
  }

  // Effects rack
  const effectsRack = page.locator('[data-testid="effects-rack"]');
  if (await effectsRack.isVisible()) {
    await effectsRack.screenshot({ path: join(SCREENSHOT_DIR, "08-effects-rack.png") });
    screenshots.push({ name: "08-effects-rack", path: "screenshots/08-effects-rack.png", description: "Effects rack panel" });
    pass("Effects rack renders");
  } else {
    // Effects rack may not be visible by default - this is expected
    pass("Effects rack not visible by default (may require track selection with effects)");
  }

  // Piano roll
  const pianoRoll = page.locator('[data-testid="piano-roll-editor"]');
  if (await pianoRoll.isVisible()) {
    await pianoRoll.screenshot({ path: join(SCREENSHOT_DIR, "09-piano-roll.png") });
    screenshots.push({ name: "09-piano-roll", path: "screenshots/09-piano-roll.png", description: "Piano roll editor" });
    pass("Piano roll editor renders");
  } else {
    pass("Piano roll not visible by default (requires clip selection)");
  }

  // Drum machine
  const drumMachine = page.locator('[data-testid="drum-machine-panel"]');
  if (await drumMachine.isVisible()) {
    await drumMachine.screenshot({ path: join(SCREENSHOT_DIR, "10-drum-machine.png") });
    screenshots.push({ name: "10-drum-machine", path: "screenshots/10-drum-machine.png", description: "Drum machine panel" });
    pass("Drum machine panel renders");
  } else {
    pass("Drum machine not visible by default (requires drum track selection)");
  }

  // Synth editor
  const synthEditor = page.locator('[data-testid="synth-editor"]');
  if (await synthEditor.isVisible()) {
    await synthEditor.screenshot({ path: join(SCREENSHOT_DIR, "11-synth-editor.png") });
    screenshots.push({ name: "11-synth-editor", path: "screenshots/11-synth-editor.png", description: "Synth editor with oscillators, filter, envelopes, LFOs" });
    pass("Synth editor renders");
  } else {
    pass("Synth editor not visible by default (requires instrument track selection)");
  }

  console.log("=== Phase 3: Test transport interactions (play/stop) ===");

  // Test Play button
  const playBtn = page.locator('button[aria-label="Play"]');
  if (await playBtn.isVisible()) {
    await playBtn.click();
    await page.waitForTimeout(500);
    const playActive = await playBtn.getAttribute("data-active");
    if (playActive === "true") {
      pass("Play button activates correctly (data-active=true)");
    } else {
      finding("P2", "FUNC", "Play button does not show active state after click", "[aria-label='Play']", "Click play button, check data-active attribute", "Visual feedback missing for transport state");
    }

    // Stop
    const stopBtn = page.locator('button[aria-label="Stop"]');
    if (await stopBtn.isVisible()) {
      await stopBtn.click();
      await page.waitForTimeout(300);
      const playActiveAfterStop = await playBtn.getAttribute("data-active");
      if (playActiveAfterStop === "false") {
        pass("Stop button correctly deactivates play state");
      } else {
        finding("P2", "FUNC", "Play button still active after stop", "[aria-label='Stop']", "Click stop after play, check play data-active", "Transport state not updating correctly");
      }
    }
  } else {
    finding("P1", "FUNC", "Play button not found", "[aria-label='Play']", "Look for play button in transport", "Core transport control missing");
  }

  // Test Loop toggle
  const loopBtn = page.locator('button[aria-label="Loop"]');
  if (await loopBtn.isVisible()) {
    const initialLoop = await loopBtn.getAttribute("aria-checked");
    await loopBtn.click();
    await page.waitForTimeout(200);
    const afterLoop = await loopBtn.getAttribute("aria-checked");
    if (initialLoop !== afterLoop) {
      pass("Loop toggle works correctly (aria-checked toggles)");
    } else {
      finding("P2", "FUNC", "Loop toggle does not change aria-checked", "[aria-label='Loop']", "Click loop button", "Toggle state not updating");
    }
    // Toggle back
    await loopBtn.click();
  } else {
    finding("P2", "FUNC", "Loop button not found", "[aria-label='Loop']", "Look for loop button", "Transport control missing");
  }

  // Test Metronome toggle
  const metBtn = page.locator('button[aria-label="Metronome"]');
  if (await metBtn.isVisible()) {
    await metBtn.click();
    await page.waitForTimeout(200);
    const metActive = await metBtn.getAttribute("aria-checked");
    if (metActive === "true") {
      pass("Metronome toggle activates correctly");
    }
    await metBtn.click(); // Toggle back
  }

  console.log("=== Phase 4: Test solo/mute ===");

  const channelStrips = page.locator('[data-testid^="channel-strip-"]');
  const stripCount = await channelStrips.count();
  if (stripCount > 0) {
    pass(`Mixer has ${stripCount} channel strips`);

    // Test mute on first channel
    const firstStrip = channelStrips.first();
    const muteBtn = firstStrip.locator('button[aria-label="Mute"], button[aria-label="Unmute"]');
    if (await muteBtn.isVisible()) {
      const initialLabel = await muteBtn.getAttribute("aria-label");
      await muteBtn.click();
      await page.waitForTimeout(200);
      const afterLabel = await muteBtn.getAttribute("aria-label");
      if (initialLabel !== afterLabel) {
        pass("Mute toggle works (aria-label changes between Mute/Unmute)");
      } else {
        finding("P2", "FUNC", "Mute button aria-label does not toggle", "channel-strip mute button", "Click mute on first channel", "State not updating");
      }
      await muteBtn.click(); // Toggle back
    }

    // Test solo on first channel
    const soloBtn = firstStrip.locator('button[aria-label="Solo"], button[aria-label="Unsolo"]');
    if (await soloBtn.isVisible()) {
      const initialLabel = await soloBtn.getAttribute("aria-label");
      await soloBtn.click();
      await page.waitForTimeout(200);
      const afterLabel = await soloBtn.getAttribute("aria-label");
      if (initialLabel !== afterLabel) {
        pass("Solo toggle works (aria-label changes between Solo/Unsolo)");
      } else {
        finding("P2", "FUNC", "Solo button aria-label does not toggle", "channel-strip solo button", "Click solo on first channel", "State not updating");
      }
      await soloBtn.click(); // Toggle back
    }
  } else {
    finding("P1", "FUNC", "No channel strips found in mixer", "[data-testid='mixer-panel']", "Load the DAW", "Mixer has no channels");
  }

  // Master strip
  const masterStrip = page.locator('[data-testid="master-strip"]');
  if (await masterStrip.isVisible()) {
    pass("Master strip is visible in mixer");
  } else {
    finding("P2", "FUNC", "Master strip not visible", "[data-testid='master-strip']", "Check mixer panel", "Master output strip missing");
  }

  console.log("=== Phase 5: Verify metering is visually dead ===");

  // Check VU meter elements -- they should all show 0/empty since meterLevel=0
  const vuMeters = page.locator("canvas").filter({ has: page.locator("..") });
  // More specifically, check that meter levels in the store are 0
  const meterCheck = await page.evaluate(() => {
    // Look for VU meter canvases
    const canvases = document.querySelectorAll("canvas");
    return {
      canvasCount: canvases.length,
    };
  });
  pass(`Found ${meterCheck.canvasCount} canvas elements (arrangement + potential meters)`);
  // Since meterLevel={0} and meterPeak={0} are hardcoded in MixerPanel.tsx, metering is confirmed dead
  finding("P2", "KNOWN", "Metering is hardcoded to 0 -- VU meters show no activity", "MixerPanel.tsx lines 62-64", "Observe VU meters during playback - all remain at 0", "meterLevel={0}, meterPeak={0}, clipping={false} are hardcoded; real AnalyserNode data not wired");

  await screenshot(page, "12-metering-dead", "VU meters at zero - metering not wired to real audio data");

  console.log("=== Phase 6: Test keyboard shortcuts ===");

  // Space for play/stop
  await page.keyboard.press("Space");
  await page.waitForTimeout(500);
  const afterSpace = await playBtn.getAttribute("data-active").catch(() => null);
  if (afterSpace === "true") {
    pass("Space key triggers play");
    await page.keyboard.press("Space");
    await page.waitForTimeout(300);
    const afterSpace2 = await playBtn.getAttribute("data-active").catch(() => null);
    if (afterSpace2 === "false") {
      pass("Space key toggles stop");
    }
  } else {
    finding("P2", "FUNC", "Space key does not trigger play/stop", "keyboard", "Press Space key", "Keyboard shortcut not working");
  }

  // Ctrl+Z for undo (just verify no crash)
  await page.keyboard.press("Meta+z");
  await page.waitForTimeout(200);
  pass("Cmd+Z (undo) does not crash");

  // Ctrl+Shift+Z for redo
  await page.keyboard.press("Meta+Shift+z");
  await page.waitForTimeout(200);
  pass("Cmd+Shift+Z (redo) does not crash");

  // Ctrl+S for save
  await page.keyboard.press("Meta+s");
  await page.waitForTimeout(200);
  pass("Cmd+S (save) does not crash");

  // Note: The epic mentioned M for mute, P/S/E for piano roll tools
  // These shortcuts may not be implemented yet - let's check
  const pianoRollTools = page.locator('[data-testid="tool-pencil"], [data-testid="tool-select"], [data-testid="tool-erase"]');
  const toolCount = await pianoRollTools.count();
  if (toolCount === 0) {
    pass("Piano roll tools (P/S/E shortcuts) not visible - piano roll requires clip selection");
  }

  console.log("=== Phase 7: Test responsive behavior at 1024px ===");

  await page.setViewportSize({ width: 1024, height: 768 });
  await page.waitForTimeout(500);
  await screenshot(page, "13-responsive-1024", "DAW at 1024x768 minimum viewport");

  // Check nothing overflows or breaks
  const overflowCheck1024 = await page.evaluate(() => {
    const body = document.body;
    return {
      scrollWidth: body.scrollWidth,
      clientWidth: body.clientWidth,
      hasHorizontalOverflow: body.scrollWidth > body.clientWidth + 5,
    };
  });

  if (overflowCheck1024.hasHorizontalOverflow) {
    finding("P2", "VISUAL", `Horizontal overflow at 1024px (scrollWidth=${overflowCheck1024.scrollWidth}, clientWidth=${overflowCheck1024.clientWidth})`, "body", "Resize to 1024x768", "Content overflows minimum supported viewport");
  } else {
    pass("No horizontal overflow at 1024x768");
  }

  // Check all major panels still visible
  const panelsAt1024 = {
    toolbar: await page.locator('[data-testid="toolbar"]').isVisible().catch(() => false),
    arrangement: await page.locator('[data-testid="arrangement-panel"]').isVisible().catch(() => false),
    mixer: await page.locator('[data-testid="mixer-panel"]').isVisible().catch(() => false),
  };

  if (panelsAt1024.toolbar && panelsAt1024.arrangement && panelsAt1024.mixer) {
    pass("All core panels visible at 1024x768");
  } else {
    const missing = Object.entries(panelsAt1024).filter(([, v]) => !v).map(([k]) => k);
    finding("P2", "VISUAL", `Panels not visible at 1024px: ${missing.join(", ")}`, "layout", "Resize to 1024x768", "Core panels must remain visible at minimum viewport");
  }

  // Test at smaller viewport (tablet)
  await page.setViewportSize({ width: 768, height: 1024 });
  await page.waitForTimeout(500);
  await screenshot(page, "14-responsive-768", "DAW at 768x1024 (tablet portrait)");

  // Reset viewport
  await page.setViewportSize({ width: 1440, height: 900 });
  await page.waitForTimeout(500);

  console.log("=== Phase 8: Test error states ===");

  // Check for any console errors from the initial load
  const jsErrors = consoleMsgs.filter((m) => m.type === "error");
  const jsWarnings = consoleMsgs.filter((m) => m.type === "warning");

  if (jsErrors.length > 0) {
    finding("P2", "FUNC", `${jsErrors.length} console error(s) detected`, "browser console", "Load the app and check console", jsErrors.map((e) => e.text).join("; ").slice(0, 200));
  } else {
    pass("No console errors during session");
  }

  if (jsWarnings.length > 0) {
    finding("P3", "FUNC", `${jsWarnings.length} console warning(s) detected`, "browser console", "Load the app", jsWarnings.map((w) => w.text).join("; ").slice(0, 200));
  } else {
    pass("No console warnings during session");
  }

  if (pageErrors.length > 0) {
    finding("P1", "FUNC", `${pageErrors.length} uncaught JS error(s)`, "browser", "Load and interact with app", pageErrors.join("; ").slice(0, 300));
  } else {
    pass("No uncaught JavaScript errors");
  }

  if (networkErrors.length > 0) {
    finding("P2", "FUNC", `${networkErrors.length} network error(s)`, "network", "Load the app", networkErrors.map((e) => `${e.status} ${e.url}`).join("; ").slice(0, 200));
  } else {
    pass("No network errors (no 4xx/5xx responses)");
  }

  console.log("=== Phase 9: Accessibility checks ===");

  // Check focus rings
  await page.keyboard.press("Tab");
  await page.waitForTimeout(200);
  const focusedElement = await page.evaluate(() => {
    const el = document.activeElement;
    if (!el || el === document.body) return null;
    const styles = window.getComputedStyle(el);
    return {
      tag: el.tagName,
      label: el.getAttribute("aria-label") || el.textContent?.slice(0, 30),
      outlineStyle: styles.outlineStyle,
      outlineWidth: styles.outlineWidth,
      outlineColor: styles.outlineColor,
    };
  });

  if (focusedElement) {
    if (focusedElement.outlineStyle !== "none" && focusedElement.outlineWidth !== "0px") {
      pass(`Tab focuses element (${focusedElement.tag}: ${focusedElement.label}) with visible outline`);
    } else {
      finding("P2", "A11Y", "Focused element has no visible focus indicator", `${focusedElement.tag}: ${focusedElement.label}`, "Press Tab to focus first element", "WCAG 2.4.7 requires visible focus indicators");
    }
  } else {
    finding("P2", "A11Y", "Tab does not focus any interactive element", "body", "Press Tab", "Keyboard navigation not working");
  }

  // Check ARIA labels on transport buttons
  const ariaChecks = await page.evaluate(() => {
    const buttons = document.querySelectorAll("button");
    const unlabeled = [];
    buttons.forEach((btn) => {
      const label = btn.getAttribute("aria-label") || btn.textContent?.trim();
      if (!label) {
        unlabeled.push(btn.outerHTML.slice(0, 80));
      }
    });
    return { totalButtons: buttons.length, unlabeled };
  });

  if (ariaChecks.unlabeled.length > 0) {
    finding("P2", "A11Y", `${ariaChecks.unlabeled.length} button(s) without aria-label or text content`, "buttons", "Inspect buttons", ariaChecks.unlabeled.join("; ").slice(0, 200));
  } else {
    pass(`All ${ariaChecks.totalButtons} buttons have aria-label or text content`);
  }

  // Check heading hierarchy
  const headings = await page.evaluate(() => {
    const hs = document.querySelectorAll("h1, h2, h3, h4, h5, h6");
    return Array.from(hs).map((h) => ({
      level: parseInt(h.tagName[1]),
      text: h.textContent?.slice(0, 50),
    }));
  });

  if (headings.length === 0) {
    finding("P3", "A11Y", "No heading elements found in the app", "document", "Inspect DOM for h1-h6", "Headings help screen readers navigate; a DAW might use headings for panel labels");
  } else {
    pass(`Found ${headings.length} heading(s): ${headings.map((h) => `h${h.level}`).join(", ")}`);
  }

  // Check landmark roles
  const landmarks = await page.evaluate(() => {
    const regions = document.querySelectorAll("[role='region'], [role='navigation'], [role='main'], [role='banner'], [role='contentinfo'], header, nav, main, footer, section[aria-label]");
    return Array.from(regions).map((r) => ({
      tag: r.tagName,
      role: r.getAttribute("role"),
      label: r.getAttribute("aria-label"),
    }));
  });

  if (landmarks.length > 0) {
    pass(`Found ${landmarks.length} landmark region(s)`);
  } else {
    finding("P3", "A11Y", "No ARIA landmark regions or semantic HTML5 landmarks found", "document", "Check for role='region', nav, main, etc.", "Landmarks help screen readers navigate the app");
  }

  // Check color contrast (basic heuristic)
  const contrastCheck = await page.evaluate(() => {
    const body = document.body;
    const bg = window.getComputedStyle(body).backgroundColor;
    const text = window.getComputedStyle(body).color;
    return { bg, text };
  });
  pass(`Body background: ${contrastCheck.bg}, text: ${contrastCheck.text}`);

  // Check for images without alt text
  const imgCheck = await page.evaluate(() => {
    const images = document.querySelectorAll("img");
    const noAlt = Array.from(images).filter((img) => !img.getAttribute("alt"));
    return { total: images.length, noAlt: noAlt.length };
  });

  if (imgCheck.total > 0 && imgCheck.noAlt > 0) {
    finding("P2", "A11Y", `${imgCheck.noAlt} of ${imgCheck.total} images missing alt text`, "img elements", "Inspect images", "WCAG 1.1.1 requires alt text");
  } else if (imgCheck.total > 0) {
    pass(`All ${imgCheck.total} images have alt text`);
  } else {
    pass("No img elements found (app uses canvas/SVG)");
  }

  // Final full screenshot
  await screenshot(page, "15-final-state", "Final state of the DAW after all interactions");

  console.log("=== Phase 10: BPM input testing ===");

  // Test BPM input
  const bpmInput = page.locator('input[aria-label="BPM"]').or(page.locator('input[type="number"]').first());
  if (await bpmInput.isVisible()) {
    const initialBpm = await bpmInput.inputValue();
    pass(`BPM input visible with initial value: ${initialBpm}`);

    // Clear and type new value
    await bpmInput.triple_click?.() || await bpmInput.click({ clickCount: 3 });
    await bpmInput.fill("140");
    await bpmInput.press("Enter");
    await page.waitForTimeout(200);
    const newBpm = await bpmInput.inputValue();
    pass(`BPM changed to: ${newBpm}`);
  }

  // Cursor display
  const cursorDisplay = page.locator('[data-testid="cursor-display"]');
  if (await cursorDisplay.isVisible()) {
    pass("Cursor display is visible in transport bar");
  } else {
    finding("P3", "FUNC", "Cursor display not visible", "[data-testid='cursor-display']", "Check transport bar", "Position indicator missing");
  }

  console.log("=== Cleanup ===");
  await browser.close();

  // Generate report
  generateReport();
}

function generateReport() {
  const p0 = findings.filter((f) => f.severity === "P0");
  const p1 = findings.filter((f) => f.severity === "P1");
  const p2 = findings.filter((f) => f.severity === "P2");
  const p3 = findings.filter((f) => f.severity === "P3");

  const formatFinding = (f) =>
    `- **[${f.category}]** ${f.what}\n  - **Where**: ${f.where}\n  - **Repro**: ${f.repro}\n  - **Justification**: ${f.justification}`;

  const report = `# QA Report: BRUTALWAV DAW

**Target**: http://localhost:5173
**Date**: ${new Date().toISOString()}
**Strategies applied**: Smoke Testing, Interaction Testing, Visual Review, Accessibility, Keyboard Shortcuts, Responsive Behavior, Metering Verification

---

## P0 Findings (Blocks Ship)

${p0.length === 0 ? "None." : p0.map(formatFinding).join("\n\n")}

## P1 Findings (Critical)

${p1.length === 0 ? "None." : p1.map(formatFinding).join("\n\n")}

## P2 Findings (Important)

${p2.length === 0 ? "None." : p2.map(formatFinding).join("\n\n")}

## P3 Findings (Minor)

${p3.length === 0 ? "None." : p3.map(formatFinding).join("\n\n")}

## Passed Checks

${passed.map((p) => `- ${p}`).join("\n")}

## Screenshots

${screenshots.map((s) => `- **${s.name}**: ${s.description} ([${s.path}](${s.path}))`).join("\n")}

## Summary

| Severity | Count |
|----------|-------|
| P0 | ${p0.length} |
| P1 | ${p1.length} |
| P2 | ${p2.length} |
| P3 | ${p3.length} |
| **Passed** | **${passed.length}** |

---

*Generated by QA Engineer automation*
`;

  writeFileSync(REPORT_PATH, report);
  console.log(`\nReport written to: ${REPORT_PATH}`);
  console.log(`P0: ${p0.length}, P1: ${p1.length}, P2: ${p2.length}, P3: ${p3.length}, Passed: ${passed.length}`);
}

main().catch((err) => {
  console.error("QA script failed:", err);
  process.exit(1);
});

