/**
 * QA Browser Automation Script for BRUTALWAV DAW
 * Tests all major panels, interactions, keyboard shortcuts, metering, responsive behavior, and accessibility.
 * Mocks AudioContext for headless browser compatibility.
 */

import { chromium } from "playwright";
import { writeFileSync, mkdirSync } from "fs";
import { join } from "path";

const BASE_URL = "http://localhost:5173";
const SCREENSHOT_DIR = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/screenshots";
const REPORT_PATH = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/qa-report.md";

mkdirSync(SCREENSHOT_DIR, { recursive: true });

const findings = [];
const passed = [];
const screenshots = [];

function finding(severity, category, what, where, repro, justification) {
  findings.push({ severity, category, what, where, repro, justification });
}

function pass(description) {
  passed.push(description);
}

async function screenshotFn(page, name, description) {
  const path = join(SCREENSHOT_DIR, `${name}.png`);
  await page.screenshot({ path, fullPage: false });
  screenshots.push({ name, path: `screenshots/${name}.png`, description });
  return path;
}

async function elementScreenshot(page, locator, name, description) {
  const path = join(SCREENSHOT_DIR, `${name}.png`);
  try {
    if (await locator.isVisible()) {
      await locator.screenshot({ path });
      screenshots.push({ name, path: `screenshots/${name}.png`, description });
      return true;
    }
  } catch {
    // Ignore screenshot errors
  }
  return false;
}

// Mock AudioContext for headless browser
const AUDIO_CONTEXT_MOCK = `
  // Mock AudioWorklet
  class MockAudioWorkletNode {
    constructor() {
      this.port = { postMessage() {}, onmessage: null, start() {} };
      this.connect = () => this;
      this.disconnect = () => {};
      this.parameters = new Map();
    }
  }

  const OriginalAudioContext = window.AudioContext;

  class MockAudioContext {
    constructor() {
      this.state = 'suspended';
      this.sampleRate = 48000;
      this.currentTime = 0;
      this.destination = {
        channelCount: 2,
        connect: () => this.destination,
        disconnect: () => {}
      };
      this.audioWorklet = {
        addModule: () => Promise.resolve()
      };
      this._nodes = [];
    }

    async resume() {
      this.state = 'running';
    }

    async close() {
      this.state = 'closed';
    }

    async suspend() {
      this.state = 'suspended';
    }

    createGain() {
      const node = {
        gain: { value: 1, setValueAtTime() {}, linearRampToValueAtTime() {}, exponentialRampToValueAtTime() {} },
        connect: () => node,
        disconnect: () => {},
        channelCount: 2,
      };
      return node;
    }

    createOscillator() {
      const node = {
        type: 'sine',
        frequency: { value: 440, setValueAtTime() {}, linearRampToValueAtTime() {}, exponentialRampToValueAtTime() {} },
        detune: { value: 0, setValueAtTime() {} },
        connect: () => node,
        disconnect: () => {},
        start() {},
        stop() {},
      };
      return node;
    }

    createAnalyser() {
      return {
        fftSize: 2048,
        frequencyBinCount: 1024,
        connect: (n) => n,
        disconnect: () => {},
        getByteTimeDomainData: (arr) => arr.fill(128),
        getByteFrequencyData: (arr) => arr.fill(0),
        getFloatTimeDomainData: (arr) => arr.fill(0),
        getFloatFrequencyData: (arr) => arr.fill(-100),
      };
    }

    createBiquadFilter() {
      const node = {
        type: 'lowpass',
        frequency: { value: 350, setValueAtTime() {}, linearRampToValueAtTime() {} },
        Q: { value: 1, setValueAtTime() {} },
        gain: { value: 0, setValueAtTime() {} },
        connect: () => node,
        disconnect: () => {},
      };
      return node;
    }

    createDynamicsCompressor() {
      const node = {
        threshold: { value: -24 },
        knee: { value: 30 },
        ratio: { value: 12 },
        attack: { value: 0.003 },
        release: { value: 0.25 },
        reduction: 0,
        connect: () => node,
        disconnect: () => {},
      };
      return node;
    }

    createConvolver() {
      return { buffer: null, connect: (n) => n, disconnect: () => {} };
    }

    createDelay() {
      return {
        delayTime: { value: 0, setValueAtTime() {} },
        connect: (n) => n,
        disconnect: () => {},
      };
    }

    createStereoPanner() {
      return {
        pan: { value: 0, setValueAtTime() {} },
        connect: (n) => n,
        disconnect: () => {},
      };
    }

    createWaveShaper() {
      return { curve: null, oversample: 'none', connect: (n) => n, disconnect: () => {} };
    }

    createChannelSplitter() {
      return { connect: (n) => n, disconnect: () => {} };
    }

    createChannelMerger() {
      return { connect: (n) => n, disconnect: () => {} };
    }

    createBuffer(channels, length, sampleRate) {
      const data = [];
      for (let i = 0; i < channels; i++) data.push(new Float32Array(length));
      return {
        numberOfChannels: channels,
        length,
        sampleRate,
        duration: length / sampleRate,
        getChannelData: (ch) => data[ch] || new Float32Array(length),
      };
    }

    createBufferSource() {
      const node = {
        buffer: null,
        loop: false,
        loopStart: 0,
        loopEnd: 0,
        playbackRate: { value: 1 },
        connect: () => node,
        disconnect: () => {},
        start() {},
        stop() {},
        onended: null,
      };
      return node;
    }

    async decodeAudioData(buffer) {
      return this.createBuffer(2, 48000, 48000);
    }
  }

  window.AudioContext = MockAudioContext;
  window.webkitAudioContext = MockAudioContext;

  // Mock SharedArrayBuffer if not available (COOP/COEP may not work in automation)
  if (typeof SharedArrayBuffer === 'undefined') {
    window.SharedArrayBuffer = ArrayBuffer;
  }
`;

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
