  await page.waitForTimeout(1500);

  const dawShellVisible = await page.locator('[data-testid="daw-shell"]').isVisible().catch(() => false);
  if (dawShellVisible) {
    pass("DawShell renders after clicking start (AudioContext mock working)");
  } else {
