    // Check console for errors
    const startErrors = consoleMsgs.filter(m => m.type === 'error');
    const errorInfo = startErrors.length > 0 ? startErrors.map(e => e.text).join("; ").slice(0, 300) : "No console errors";
    const pageErrorInfo = pageErrors.length > 0 ? pageErrors.join("; ").slice(0, 300) : "No page errors";

    finding("P1", "INFRA", "DawShell fails to render after clicking start in headless browser", BASE_URL,
      "Click the start overlay to init audio engine",
      `AudioContext mock may be incomplete. Console errors: ${errorInfo}. Page errors: ${pageErrorInfo}`);

    // Continue testing what we can
    console.log("Continuing with limited testing scope...");
  }

  // Full DAW screenshot
  await screenshotFn(page, "02-daw-full-view", "Full DAW view at 1440x900");

  console.log("=== Phase 2: Screenshot all major panels ===");

  // Transport bar
  const toolbar = page.locator('[data-testid="toolbar"]');
  if (await toolbar.isVisible().catch(() => false)) {
    await elementScreenshot(page, toolbar, "03-transport-bar", "Transport bar with BPM, play/stop, loop, metronome");
    pass("Transport bar renders with controls");

    // Check transport controls exist
    const playBtn = page.locator('button[aria-label="Play"]');
    const stopBtn = page.locator('button[aria-label="Stop"]');
    const loopBtn = page.locator('button[aria-label="Loop"]');
    const metBtn = page.locator('button[aria-label="Metronome"]');

    const controlsPresent = {
