    };

    const presentList = Object.entries(controlsPresent).filter(([,v]) => v).map(([k]) => k);
    const missingList = Object.entries(controlsPresent).filter(([,v]) => !v).map(([k]) => k);

    if (presentList.length > 0) pass(`Transport controls present: ${presentList.join(", ")}`);
    if (missingList.length > 0) finding("P2", "FUNC", `Transport controls missing: ${missingList.join(", ")}`, "[data-testid='toolbar']", "Check transport bar", "Expected all transport controls to be present");

    // Check BRUTALWAV brand
    const brand = await page.locator("text=BRUTALWAV").isVisible().catch(() => false);
