  } else {
    finding("P1", "FUNC", "Transport bar not visible", "[data-testid='toolbar']", "Load the DAW", "Core UI element missing");
  }

  // Arrangement panel
  const arrangement = page.locator('[data-testid="arrangement-panel"]');
  if (await arrangement.isVisible().catch(() => false)) {
    await elementScreenshot(page, arrangement, "04-arrangement-panel", "Arrangement panel with tracks canvas");
