  const metBtn = page.locator('button[aria-label="Metronome"]');
  if (await metBtn.isVisible().catch(() => false)) {
    const initialMet = await metBtn.getAttribute("aria-checked");
    await metBtn.click();
    await page.waitForTimeout(200);
    const afterMet = await metBtn.getAttribute("aria-checked");
    if (initialMet !== afterMet) {
      pass("Metronome toggle works correctly");
