    // Space for play/stop
    await page.keyboard.press("Space");
    await page.waitForTimeout(500);
    const afterSpace = await playBtn.getAttribute("data-active").catch(() => null);
    if (afterSpace === "true") {
      pass("Space key triggers play");
      await page.keyboard.press("Space");
      await page.waitForTimeout(300);
      const afterSpace2 = await playBtn.getAttribute("data-active").catch(() => null);
      if (afterSpace2 === "false") {
        pass("Space key toggles between play and stop");
      }
    } else {
      finding("P2", "FUNC", "Space key does not trigger play/stop toggle", "keyboard", "Press Space with DAW focused", "Expected: Space toggles transport.playStop");
    }

    // Cmd+Z / Cmd+Shift+Z / Cmd+S
    await page.keyboard.press("Meta+z");
    await page.waitForTimeout(100);
    pass("Cmd+Z (undo) executes without crash");

    await page.keyboard.press("Meta+Shift+z");
    await page.waitForTimeout(100);
    pass("Cmd+Shift+Z (redo) executes without crash");

    await page.keyboard.press("Meta+s");
    await page.waitForTimeout(100);
    pass("Cmd+S (save) executes without crash");
  }

  console.log("=== Phase 7: Test responsive behavior ===");

  // 1024x768 minimum
  await page.setViewportSize({ width: 1024, height: 768 });
  await page.waitForTimeout(500);
  await screenshotFn(page, "16-responsive-1024", "DAW at 1024x768 minimum viewport");

