    toolbar: await page.locator('[data-testid="toolbar"]').isVisible().catch(() => false),
    arrangement: await page.locator('[data-testid="arrangement-panel"]').isVisible().catch(() => false),
    mixer: await page.locator('[data-testid="mixer-panel"]').isVisible().catch(() => false),
  };

  const overflowCheck = await page.evaluate(() => ({
    scrollWidth: document.body.scrollWidth,
    clientWidth: document.body.clientWidth,
    hasOverflow: document.body.scrollWidth > document.body.clientWidth + 5,
  }));

  if (overflowCheck.hasOverflow) {
    finding("P2", "VISUAL", `Horizontal overflow at 1024px (${overflowCheck.scrollWidth}px > ${overflowCheck.clientWidth}px)`, "body", "Resize to 1024x768", "Content overflows minimum viewport");
  } else {
    pass("No horizontal overflow at 1024x768");
  }

  const allPanelsVisible1024 = Object.values(panelsAt1024).every(Boolean);
  if (allPanelsVisible1024) {
    pass("All core panels visible at 1024x768");
  } else {
    const missing = Object.entries(panelsAt1024).filter(([,v]) => !v).map(([k]) => k);
    finding("P2", "VISUAL", `Panels not visible at 1024px: ${missing.join(", ")}`, "layout", "Resize to 1024x768", "Core panels must remain visible at minimum viewport");
  }

