/**
 * QA Browser Automation Script for BRUTALWAV DAW
 * Tests all major panels, interactions, keyboard shortcuts, metering, responsive behavior, and accessibility.
 */

import { chromium } from "playwright";
import { writeFileSync, mkdirSync } from "fs";
import { join } from "path";

const BASE_URL = "http://localhost:5173";
const SCREENSHOT_DIR = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/screenshots";
const REPORT_PATH = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/qa-report.md";

mkdirSync(SCREENSHOT_DIR, { recursive: true });

const findings = [];
const passed = [];
const screenshots = [];

function finding(severity, category, what, where, repro, justification) {
  findings.push({ severity, category, what, where, repro, justification });
}

function pass(description) {
  passed.push(description);
}

async function screenshot(page, name, description) {
  const path = join(SCREENSHOT_DIR, `${name}.png`);
  await page.screenshot({ path, fullPage: false });
  screenshots.push({ name, path: `screenshots/${name}.png`, description });
  return path;
}

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
    // Enable cross-origin isolation by bypassing CSP for testing
  });

  // Capture console messages
  const consoleMsgs = [];
  const pageErrors = [];

  const page = await context.newPage();
  page.on("console", (msg) => consoleMsgs.push({ type: msg.type(), text: msg.text() }));
  page.on("pageerror", (err) => pageErrors.push(err.message));

  // Network tracking
  const networkErrors = [];
  page.on("response", (res) => {
    if (res.status() >= 400) {
      networkErrors.push({ url: res.url(), status: res.status() });
    }
  });

  console.log("=== Phase 1: Navigate to app ===");
  try {
    await page.goto(BASE_URL, { waitUntil: "networkidle", timeout: 15000 });
  } catch (e) {
    console.error("Failed to navigate:", e.message);
    finding("P0", "INFRA", "App failed to load", BASE_URL, "Navigate to " + BASE_URL, "Application not reachable");
    await browser.close();
    generateReport();
    return;
  }

  // Screenshot initial state (ClickToStart screen)
  await screenshot(page, "01-click-to-start", "Initial ClickToStart screen before audio engine init");

  // Check cross-origin isolation
  const crossOriginOk = await page.evaluate(() => window.crossOriginIsolated);
  if (crossOriginOk) {
    pass("Cross-origin isolation is active (COOP/COEP headers working)");
  } else {
    finding("P1", "INFRA", "Cross-origin isolation not active", BASE_URL, "Check window.crossOriginIsolated", "SharedArrayBuffer and AudioWorklet require cross-origin isolation");
  }

  // Check what's on screen
  const clickToStartVisible = await page.locator("text=Click to Start").isVisible().catch(() => false);
  const crossOriginErrorVisible = await page.locator("text=Cross-Origin").isVisible().catch(() => false);

  if (crossOriginErrorVisible) {
    await screenshot(page, "02-cross-origin-error", "CrossOriginError screen shown");
