import { chromium } from "playwright";

const AUDIO_CONTEXT_MOCK = `
  class MockAudioContext {
    constructor() {
      this.state = 'suspended';
      this.sampleRate = 48000;
      this.currentTime = 0;
      this.destination = { channelCount: 2, connect() { return this; }, disconnect() {} };
      this.audioWorklet = { addModule: () => Promise.resolve() };
    }
    async resume() { this.state = 'running'; }
    async close() { this.state = 'closed'; }
    async suspend() { this.state = 'suspended'; }
    createGain() { const n = { gain: { value: 1, setValueAtTime(){}, linearRampToValueAtTime(){}, exponentialRampToValueAtTime(){} }, connect() { return n; }, disconnect(){} }; return n; }
    createOscillator() { const n = { type:'sine', frequency:{value:440,setValueAtTime(){},linearRampToValueAtTime(){},exponentialRampToValueAtTime(){}}, detune:{value:0,setValueAtTime(){}}, connect(){return n;}, disconnect(){}, start(){}, stop(){} }; return n; }
    createAnalyser() { return { fftSize:2048, frequencyBinCount:1024, connect(n){return n;}, disconnect(){}, getByteTimeDomainData(a){a.fill(128);}, getByteFrequencyData(a){a.fill(0);}, getFloatTimeDomainData(a){a.fill(0);}, getFloatFrequencyData(a){a.fill(-100);} }; }
    createBiquadFilter() { const n = { type:'lowpass', frequency:{value:350,setValueAtTime(){},linearRampToValueAtTime(){}}, Q:{value:1,setValueAtTime(){}}, gain:{value:0,setValueAtTime(){}}, connect(){return n;}, disconnect(){} }; return n; }
    createDynamicsCompressor() { const n = { threshold:{value:-24}, knee:{value:30}, ratio:{value:12}, attack:{value:0.003}, release:{value:0.25}, reduction:0, connect(){return n;}, disconnect(){} }; return n; }
    createConvolver() { return { buffer:null, connect(n){return n;}, disconnect(){} }; }
    createDelay() { return { delayTime:{value:0,setValueAtTime(){}}, connect(n){return n;}, disconnect(){} }; }
    createStereoPanner() { return { pan:{value:0,setValueAtTime(){}}, connect(n){return n;}, disconnect(){} }; }
    createWaveShaper() { return { curve:null, oversample:'none', connect(n){return n;}, disconnect(){} }; }
    createChannelSplitter() { return { connect(n){return n;}, disconnect(){} }; }
    createChannelMerger() { return { connect(n){return n;}, disconnect(){} }; }
    createBuffer(ch, len, sr) { const d=[]; for(let i=0;i<ch;i++) d.push(new Float32Array(len)); return { numberOfChannels:ch, length:len, sampleRate:sr, duration:len/sr, getChannelData(c){return d[c]||new Float32Array(len);} }; }
    createBufferSource() { const n = { buffer:null, loop:false, loopStart:0, loopEnd:0, playbackRate:{value:1}, connect(){return n;}, disconnect(){}, start(){}, stop(){}, onended:null }; return n; }
    async decodeAudioData(buf) { return this.createBuffer(2, 48000, 48000); }
  }
  window.AudioContext = MockAudioContext;
  window.webkitAudioContext = MockAudioContext;
  if (typeof SharedArrayBuffer === 'undefined') { window.SharedArrayBuffer = ArrayBuffer; }
`;

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 } });
  await context.addInitScript(AUDIO_CONTEXT_MOCK);

  const page = await context.newPage();

  // Capture ALL console output
  page.on("console", (msg) => console.log(`[CONSOLE ${msg.type()}] ${msg.text()}`));
  page.on("pageerror", (err) => console.log(`[PAGE ERROR] ${err.message}`));

  await page.goto("http://localhost:5173", { waitUntil: "networkidle", timeout: 15000 });
  console.log("\n--- Page loaded, clicking start ---\n");

  const startBtn = page.getByRole("button", { name: "BRUTALWAV Click to start" });
  if (await startBtn.isVisible()) {
    await startBtn.click();
  }

  // Wait longer
  await page.waitForTimeout(3000);

  const dawShell = await page.locator('[data-testid="daw-shell"]').isVisible().catch(() => false);
  console.log(`\nDawShell visible: ${dawShell}`);

  // Check React state
  const pageState = await page.evaluate(() => {
    // Check what's in the DOM
    const all = document.querySelectorAll('[data-testid]');
    return {
      testIds: Array.from(all).map(el => el.getAttribute('data-testid')),
      bodyHTML: document.body.innerHTML.slice(0, 500),
    };
  });

  console.log("\nTest IDs found:", pageState.testIds);
  console.log("\nBody HTML:", pageState.bodyHTML);

  await browser.close();
}

main().catch(console.error);

