// Mock AudioContext for headless browser
const AUDIO_CONTEXT_MOCK = `
  // Mock AudioWorklet
  class MockAudioWorkletNode {
    constructor() {
      this.port = { postMessage() {}, onmessage: null, start() {} };
      this.connect = () => this;
      this.disconnect = () => {};
      this.parameters = new Map();
    }
  }

  const OriginalAudioContext = window.AudioContext;

  class MockAudioContext {
    constructor() {
      this.state = 'suspended';
      this.sampleRate = 48000;
      this.currentTime = 0;
      this.destination = {
        channelCount: 2,
        connect: () => this.destination,
        disconnect: () => {}
      };
      this.audioWorklet = {
        addModule: () => Promise.resolve()
      };
      this._nodes = [];
    }

    async resume() {
      this.state = 'running';
    }

    async close() {
      this.state = 'closed';
    }

    async suspend() {
      this.state = 'suspended';
    }

    createGain() {
      const node = {
        gain: { value: 1, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        connect: () => node,
        disconnect: () => {},
        channelCount: 2,
      };
      return node;
    }

    createOscillator() {
      const node = {
        type: 'sine',
        frequency: { value: 440, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        detune: { value: 0, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        connect: () => node,
        disconnect: () => {},
        start() {},
        stop() {},
      };
      return node;
    }

    createAnalyser() {
      return {
        fftSize: 2048,
        frequencyBinCount: 1024,
        connect: (n) => n,
        disconnect: () => {},
        getByteTimeDomainData: (arr) => arr.fill(128),
        getByteFrequencyData: (arr) => arr.fill(0),
        getFloatTimeDomainData: (arr) => arr.fill(0),
        getFloatFrequencyData: (arr) => arr.fill(-100),
      };
    }

    createBiquadFilter() {
      const node = {
        type: 'lowpass',
        frequency: { value: 350, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        Q: { value: 1, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        gain: { value: 0, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        connect: () => node,
        disconnect: () => {},
      };
      return node;
    }

    createDynamicsCompressor() {
      const node = {
        threshold: { value: -24 },
        knee: { value: 30 },
        ratio: { value: 12 },
        attack: { value: 0.003 },
        release: { value: 0.25 },
        reduction: 0,
        connect: () => node,
        disconnect: () => {},
      };
      return node;
    }

    createConvolver() {
      return { buffer: null, connect: (n) => n, disconnect: () => {} };
    }

    createDelay() {
      return {
        delayTime: { value: 0, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        connect: (n) => n,
        disconnect: () => {},
      };
    }

    createStereoPanner() {
      return {
        pan: { value: 0, setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;}, exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;}, cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;} },
        connect: (n) => n,
        disconnect: () => {},
      };
    }

    createWaveShaper() {
      return { curve: null, oversample: 'none', connect: (n) => n, disconnect: () => {} };
    }

    createChannelSplitter() {
      return { connect: (n) => n, disconnect: () => {} };
    }

    createChannelMerger() {
      return { connect: (n) => n, disconnect: () => {} };
    }

    createBuffer(channels, length, sampleRate) {
      const data = [];
      for (let i = 0; i < channels; i++) data.push(new Float32Array(length));
      return {
        numberOfChannels: channels,
        length,
        sampleRate,
        duration: length / sampleRate,
        getChannelData: (ch) => data[ch] || new Float32Array(length),
      };
    }

    createBufferSource() {
      const node = {
        buffer: null,
        loop: false,
        loopStart: 0,
        loopEnd: 0,
        playbackRate: { value: 1 },
        connect: () => node,
        disconnect: () => {},
        start() {},
        stop() {},
        onended: null,
      };
      return node;
    }

    async decodeAudioData(buffer) {
      return this.createBuffer(2, 48000, 48000);
    }
  }

  window.AudioContext = MockAudioContext;
