/**
 * QA Browser Automation Script for BRUTALWAV DAW
 * Mocks AudioContext for headless browser compatibility.
 */
import { chromium } from "playwright";
import { writeFileSync, mkdirSync } from "fs";
import { join } from "path";

const BASE_URL = "http://localhost:5173";
const SCREENSHOT_DIR = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/screenshots";
const REPORT_PATH = "/Users/Nathan/Documents/Code/long-running-harness/docs/qa/qa-report.md";
mkdirSync(SCREENSHOT_DIR, { recursive: true });

const findings = [];
const passed = [];
const screenshots = [];

function finding(sev, cat, what, where, repro, just) { findings.push({ severity: sev, category: cat, what, where, repro, justification: just }); }
function pass(desc) { passed.push(desc); }

async function shot(page, name, desc) {
  const p = join(SCREENSHOT_DIR, `${name}.png`);
  await page.screenshot({ path: p, fullPage: false });
  screenshots.push({ name, path: `screenshots/${name}.png`, description: desc });
}

async function elShot(page, loc, name, desc) {
  try {
    if (await loc.isVisible()) {
      const p = join(SCREENSHOT_DIR, `${name}.png`);
      await loc.screenshot({ path: p });
      screenshots.push({ name, path: `screenshots/${name}.png`, description: desc });
      return true;
    }
  } catch { /* ignore */ }
  return false;
}

const MOCK = `
  function ap(v) {
    return { value: v,
      setValueAtTime(){return this;}, linearRampToValueAtTime(){return this;},
      exponentialRampToValueAtTime(){return this;}, setTargetAtTime(){return this;},
      cancelScheduledValues(){return this;}, cancelAndHoldAtTime(){return this;}
    };
  }
  function nd(extra) { const n = { connect(){return n;}, disconnect(){}, ...extra }; return n; }
  class MockAudioContext {
    constructor() { this.state='suspended'; this.sampleRate=48000; this.currentTime=0; this.destination=nd({channelCount:2}); this.audioWorklet={addModule:()=>Promise.resolve()}; }
    async resume() { this.state='running'; }
    async close() { this.state='closed'; }
    async suspend() { this.state='suspended'; }
    createGain() { return nd({gain:ap(1),channelCount:2}); }
    createOscillator() { return nd({type:'sine',frequency:ap(440),detune:ap(0),start(){},stop(){}}); }
    createAnalyser() { return nd({fftSize:2048,frequencyBinCount:1024,getByteTimeDomainData(a){a.fill(128);},getByteFrequencyData(a){a.fill(0);},getFloatTimeDomainData(a){a.fill(0);},getFloatFrequencyData(a){a.fill(-100);}}); }
    createBiquadFilter() { return nd({type:'lowpass',frequency:ap(350),Q:ap(1),gain:ap(0)}); }
    createDynamicsCompressor() { return nd({threshold:ap(-24),knee:ap(30),ratio:ap(12),attack:ap(0.003),release:ap(0.25),reduction:0}); }
    createConvolver() { return nd({buffer:null}); }
    createDelay() { return nd({delayTime:ap(0)}); }
    createStereoPanner() { return nd({pan:ap(0)}); }
    createWaveShaper() { return nd({curve:null,oversample:'none'}); }
    createChannelSplitter() { return nd({}); }
    createChannelMerger() { return nd({}); }
    createBuffer(ch,len,sr) { const d=[]; for(let i=0;i<ch;i++) d.push(new Float32Array(len)); return {numberOfChannels:ch,length:len,sampleRate:sr,duration:len/sr,getChannelData(c){return d[c]||new Float32Array(len);}}; }
    createBufferSource() { return nd({buffer:null,loop:false,loopStart:0,loopEnd:0,playbackRate:ap(1),start(){},stop(){},onended:null}); }
    async decodeAudioData() { return this.createBuffer(2,48000,48000); }
  }
  window.AudioContext=MockAudioContext; window.webkitAudioContext=MockAudioContext;
  if(typeof SharedArrayBuffer==='undefined'){window.SharedArrayBuffer=ArrayBuffer;}
`;

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1440, height: 900 } });
  await context.addInitScript(MOCK);

  const consoleMsgs = [];
  const pageErrors = [];
  const networkErrors = [];

  const page = await context.newPage();
  page.on("console", (msg) => consoleMsgs.push({ type: msg.type(), text: msg.text() }));
  page.on("pageerror", (err) => pageErrors.push(err.message));
  page.on("response", (res) => { if (res.status() >= 400) networkErrors.push({ url: res.url(), status: res.status() }); });

  // ===== PHASE 1: Load and Start =====
  console.log("Phase 1: Navigate and start");
  await page.goto(BASE_URL, { waitUntil: "networkidle", timeout: 15000 });
  await shot(page, "01-click-to-start", "Initial ClickToStart screen");

  const crossOriginOk = await page.evaluate(() => window.crossOriginIsolated);
  if (crossOriginOk) pass("Cross-origin isolation active (COOP/COEP headers)");
  else finding("P3", "INFO", "Cross-origin isolation not active in headless test (mocked)", BASE_URL, "Check window.crossOriginIsolated", "Expected in headless automation; real browser works with Vite headers");

  // Click start
  const startBtn = page.getByRole("button", { name: "BRUTALWAV Click to start" });
  if (await startBtn.isVisible().catch(() => false)) {
    pass("ClickToStart screen renders with BRUTALWAV branding");
    await startBtn.click();
    await page.waitForSelector('[data-testid="daw-shell"]', { timeout: 5000 }).catch(() => null);
    await page.waitForTimeout(1000);
  }

  const dawOk = await page.locator('[data-testid="daw-shell"]').isVisible().catch(() => false);
  if (dawOk) {
    pass("DawShell renders after clicking start");
  } else {
    finding("P1", "INFRA", "DawShell fails to render", BASE_URL, "Click start overlay", "AudioContext mock may be incomplete");
    const errs = pageErrors.join("; ").slice(0, 200);
    if (errs) console.log("Page errors:", errs);
  }

  await shot(page, "02-daw-full-view", "Full DAW view at 1440x900");

  // ===== PHASE 2: Screenshot all panels =====
  console.log("Phase 2: Screenshot panels");

  const panelChecks = [
    { id: "toolbar", label: "Transport bar", num: "03", critical: true },
    { id: "arrangement-panel", label: "Arrangement panel", num: "04", critical: true },
    { id: "mixer-panel", label: "Mixer panel", num: "05", critical: true },
    { id: "instrument-panel", label: "Instrument panel", num: "06", critical: false },
    { id: "media-pool-panel", label: "Media pool panel", num: "07", critical: false },
    { id: "effects-rack", label: "Effects rack", num: "08", critical: false },
    { id: "synth-editor", label: "Synth editor", num: "09", critical: false },
    { id: "piano-roll-editor", label: "Piano roll editor", num: "10", critical: false },
    { id: "drum-machine-panel", label: "Drum machine", num: "11", critical: false },
    { id: "routing-matrix", label: "Routing matrix", num: "12", critical: false },
  ];

  for (const p of panelChecks) {
    const loc = page.locator(`[data-testid="${p.id}"]`);
    const vis = await loc.isVisible().catch(() => false);
    if (vis) {
      await elShot(page, loc, `${p.num}-${p.id}`, p.label);
      pass(`${p.label} renders`);
    } else if (p.critical) {
      finding("P1", "FUNC", `${p.label} not visible`, `[data-testid='${p.id}']`, "Load the DAW", "Core panel missing");
    } else {
      pass(`${p.label} not visible by default (contextual panel)`);
    }
  }

  // Channel strips and master
  const strips = page.locator('[data-testid^="channel-strip-"]');
  const stripCount = await strips.count();
  if (stripCount > 0) {
    pass(`Mixer has ${stripCount} channel strip(s)`);
    await elShot(page, strips.first(), "05b-channel-strip", "Individual channel strip");
  }

  const master = page.locator('[data-testid="master-strip"]');
  if (await master.isVisible().catch(() => false)) {
    pass("Master strip visible");
    await elShot(page, master, "05c-master-strip", "Master output strip");
  } else {
    finding("P2", "FUNC", "Master strip not visible", "[data-testid='master-strip']", "Check mixer", "Master output missing");
  }

  // ===== PHASE 3: Transport interactions =====
  console.log("Phase 3: Transport interactions");

  const playBtn = page.locator('button[aria-label="Play"]');
  const stopBtn = page.locator('button[aria-label="Stop"]');
  const loopBtn = page.locator('button[aria-label="Loop"]');
  const metBtn = page.locator('button[aria-label="Metronome"]');

  if (await playBtn.isVisible().catch(() => false)) {
    pass("Play button present");
    await playBtn.click();
    await page.waitForTimeout(500);
    const playActive = await playBtn.getAttribute("data-active");
    if (playActive === "true") pass("Play activates (data-active=true)");
    else finding("P2", "FUNC", `Play data-active=${playActive} after click`, "Play button", "Click play", "Visual feedback issue");

    if (await stopBtn.isVisible().catch(() => false)) {
      pass("Stop button present");
      await stopBtn.click();
      await page.waitForTimeout(300);
      const afterStop = await playBtn.getAttribute("data-active");
      if (afterStop === "false") pass("Stop deactivates play correctly");
      else finding("P3", "FUNC", `Play still ${afterStop} after stop`, "Stop button", "Click stop", "State feedback");
    }
    await shot(page, "13-transport-tested", "Transport after play/stop");
  }

  if (await loopBtn.isVisible().catch(() => false)) {
    const before = await loopBtn.getAttribute("aria-checked");
    await loopBtn.click();
    await page.waitForTimeout(200);
    const after = await loopBtn.getAttribute("aria-checked");
    if (before !== after) pass("Loop toggle works (aria-checked toggles)");
    else finding("P2", "FUNC", "Loop aria-checked unchanged", "Loop button", "Click loop", "Toggle broken");
    await loopBtn.click();
  }

  if (await metBtn.isVisible().catch(() => false)) {
    const before = await metBtn.getAttribute("aria-checked");
    await metBtn.click();
    await page.waitForTimeout(200);
    const after = await metBtn.getAttribute("aria-checked");
    if (before !== after) pass("Metronome toggle works");
    await metBtn.click();
  }

  // ===== PHASE 4: Solo/Mute =====
  console.log("Phase 4: Solo/Mute");

  if (stripCount > 0) {
    const first = strips.first();

    const muteBtn = first.locator("button").filter({ hasText: "M" });
    if (await muteBtn.isVisible().catch(() => false)) {
      const l1 = await muteBtn.getAttribute("aria-label");
      await muteBtn.click();
      await page.waitForTimeout(200);
      const l2 = await muteBtn.getAttribute("aria-label");
      if (l1 !== l2) pass("Mute toggle works (aria-label changes)");
      else finding("P2", "FUNC", "Mute label unchanged after click", "mute button", "Click M", "Toggle broken");
      await muteBtn.click();
      await shot(page, "14-mute-tested", "After mute toggle");
    }

    const soloBtn2 = first.locator("button").filter({ hasText: "S" });
    if (await soloBtn2.isVisible().catch(() => false)) {
      const l1 = await soloBtn2.getAttribute("aria-label");
      await soloBtn2.click();
      await page.waitForTimeout(200);
      const l2 = await soloBtn2.getAttribute("aria-label");
      if (l1 !== l2) pass("Solo toggle works (aria-label changes)");
      else finding("P2", "FUNC", "Solo label unchanged after click", "solo button", "Click S", "Toggle broken");
      await soloBtn2.click();
    }
  }

  // ===== PHASE 5: Metering verification =====
  console.log("Phase 5: Metering");

  finding("P2", "KNOWN", "Metering hardcoded to 0 -- VU meters show no activity during playback",
    "src/ui/mixer/MixerPanel.tsx:62-64",
    "Play audio, observe VU meters remain at zero",
    "meterLevel={0}, meterPeak={0}, clipping={false} are hardcoded; real AnalyserNode not wired");
  await shot(page, "15-metering-dead", "VU meters at zero - no real audio data");

  // ===== PHASE 6: Keyboard shortcuts =====
  console.log("Phase 6: Keyboard shortcuts");

  const daw = page.locator('[data-testid="daw-shell"]');
  if (await daw.isVisible().catch(() => false)) {
    await daw.click();
    await page.waitForTimeout(200);

    // Space = play/stop toggle
    await page.keyboard.press("Space");
    await page.waitForTimeout(500);
    const afterSpace = await playBtn.getAttribute("data-active").catch(() => null);
    if (afterSpace === "true") {
      pass("Space key triggers play");
      await page.keyboard.press("Space");
      await page.waitForTimeout(300);
      const after2 = await playBtn.getAttribute("data-active").catch(() => null);
      if (after2 === "false") pass("Space toggles stop");
    } else {
      finding("P2", "FUNC", "Space key does not trigger play/stop", "keyboard", "Press Space", "transport.playStop shortcut not working");
    }

    // Cmd+Z, Cmd+Shift+Z, Cmd+S
    await page.keyboard.press("Meta+z");
    await page.waitForTimeout(100);
    pass("Cmd+Z (undo) no crash");

    await page.keyboard.press("Meta+Shift+z");
    await page.waitForTimeout(100);
    pass("Cmd+Shift+Z (redo) no crash");

    await page.keyboard.press("Meta+s");
    await page.waitForTimeout(100);
    pass("Cmd+S (save) no crash");
  }

  // ===== PHASE 7: Responsive =====
  console.log("Phase 7: Responsive");

  await page.setViewportSize({ width: 1024, height: 768 });
  await page.waitForTimeout(500);
  await shot(page, "16-responsive-1024", "DAW at 1024x768 minimum viewport");

  const overflow = await page.evaluate(() => ({
    sw: document.body.scrollWidth, cw: document.body.clientWidth,
    over: document.body.scrollWidth > document.body.clientWidth + 5,
  }));
  if (overflow.over) finding("P2", "VISUAL", `Horizontal overflow at 1024px (${overflow.sw}>${overflow.cw})`, "body", "Resize to 1024x768", "Overflow at min viewport");
  else pass("No horizontal overflow at 1024x768");

  const at1024 = {
    toolbar: await page.locator('[data-testid="toolbar"]').isVisible().catch(() => false),
    arrangement: await page.locator('[data-testid="arrangement-panel"]').isVisible().catch(() => false),
    mixer: await page.locator('[data-testid="mixer-panel"]').isVisible().catch(() => false),
  };
  if (Object.values(at1024).every(Boolean)) pass("All core panels visible at 1024x768");
  else { const m = Object.entries(at1024).filter(([,v]) => !v).map(([k]) => k); finding("P2", "VISUAL", `Missing at 1024px: ${m.join(",")}`, "layout", "Resize", "Core panels must be visible"); }

  await page.setViewportSize({ width: 768, height: 1024 });
  await page.waitForTimeout(500);
  await shot(page, "17-responsive-768", "DAW at 768x1024 (tablet)");

  await page.setViewportSize({ width: 1440, height: 900 });
  await page.waitForTimeout(300);

  // ===== PHASE 8: Error states =====
  console.log("Phase 8: Errors");

  const jsErrors = consoleMsgs.filter(m => m.type === "error");
  const jsWarns = consoleMsgs.filter(m => m.type === "warning");
  const realErrors = jsErrors.filter(e => !e.text.includes("Mock") && !e.text.includes("mock"));

  if (realErrors.length > 0) finding("P2", "FUNC", `${realErrors.length} console error(s)`, "console", "Load app", realErrors.map(e => e.text).join("; ").slice(0, 300));
  else pass("No console errors during session");

  if (jsWarns.length > 0) finding("P3", "INFO", `${jsWarns.length} console warning(s)`, "console", "Load app", jsWarns.map(w => w.text).join("; ").slice(0, 200));
  else pass("No console warnings");

  if (pageErrors.length > 0) finding("P1", "FUNC", `${pageErrors.length} uncaught JS error(s)`, "browser", "Interact with app", pageErrors.join("; ").slice(0, 300));
